// Unwrap the webhook body so downstream nodes can read the Discord
// payload fields at the top level — matches the shape the Channel Router
// was originally written against.
const item = $input.item.json || {};
const body = item.body || item;
return [{ json: body }];

// Convert fetched Discord attachments into Claude API content blocks.
//   image/*         → { type: 'image',    source: { type: 'base64', media_type, data } }
//   application/pdf → { type: 'document', source: { type: 'base64', media_type, data } }
// Unsupported types (zip, txt, etc.) are silently skipped.
//
// Uses this.helpers.getBinaryDataBuffer() to handle both in-memory and
// filesystem binary storage modes — the old approach of reading binary.data
// directly only worked with in-memory mode and broke silently on filesystem-v2.
const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binary = item.binary && item.binary.data;
  if (!binary) continue;

  const mime = binary.mimeType || '';
  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
  const base64 = buffer.toString('base64');

  if (mime.startsWith('image/')) {
    results.push({
      type: 'image',
      source: { type: 'base64', media_type: mime, data: base64 }
    });
  } else if (mime === 'application/pdf') {
    results.push({
      type: 'document',
      source: { type: 'base64', media_type: 'application/pdf', data: base64 }
    });
  }
}

const msg = $('Unwrap Body').first().json;
return [{ json: { ...msg, content_blocks: results } }];

