// Extract Claude's reply text and prep the fields needed downstream.
const router = $('Channel Router').first().json;
const apiRes = $input.item.json;

const reply = (apiRes.content || [])
  .filter(c => c.type === 'text')
  .map(c => c.text)
  .join('\n\n')
  .trim();

if (!reply) {
  throw new Error('Empty reply from Claude — check response shape: ' + JSON.stringify(apiRes).slice(0, 500));
}

return [{
  json: {
    ...router,
    reply,
    // Discord caps message length at 2000 chars; truncate safely.
    replyTruncated: reply.length > 1950 ? reply.slice(0, 1950) + '…' : reply,
  }
}];

// ---------------------------------------------------------------------------
// Build Memory Extraction Request
//
// Runs on the default conversation branch only (commands like /image,
// /search, /clear, /use, /remember, /forget, /memories take separate paths
// out of Command Switch and never reach here). Fires after Persist Assistant
// Message so we have a completed exchange to analyze.
//
// Asks Haiku to extract durable facts, preferences, decisions, and
// commitments about the triggering user. Skip duplicates — the user's
// existing memories are passed in the prompt so Haiku can avoid
// re-extracting anything already captured.
//
// Shared-channel note: Channel Router's userId is always the webhook
// payload's author.id — i.e. the user whose message fired this run. In a
// shared channel with multiple speakers, only the mentioner triggers Bruce,
// so we only ever extract memories for that one user.
// ---------------------------------------------------------------------------
const router = $('Channel Router').first().json;

const existingMemories = $('Fetch User Memories').all()
  .map(i => i.json)
  .filter(r => r && r.content)
  .map(r => r.content);

const historyRows = $('Fetch Conversation History').all()
  .map(i => i.json)
  .reverse()
  .filter(r => r && (r.role === 'user' || r.role === 'assistant'))
  .filter(r => r.content != null && String(r.content).trim().length > 0);

const parsed = $('Parse Claude Reply').first().json;
const userMessageText = router.content || '';
const assistantReplyText = parsed.reply || '';
const speakerName = router.userName || 'the user';

// Last 10 prior turns plus the exchange that just completed.
const historyText = historyRows
  .slice(-10)
  .map(r => {
    const who = r.role === 'assistant' ? 'Bruce' : (r.discord_username || speakerName);
    return `${who}: ${r.content}`;
  })
  .join('\n');

const existingBlock = existingMemories.length
  ? existingMemories.map(m => `- ${m}`).join('\n')
  : '(none yet)';

const system = `You are a background memory-curation assistant for Bruce, a household AI. Your job is to extract durable, reusable facts about a specific user from a recent conversation.

Err on the side of CAPTURING rather than skipping. Bruce's job is to feel like a family member who remembers things — a missed fact is a bigger failure than a redundant one.

ALWAYS capture (highest priority — these are load-bearing for future replies):
- Health info: allergies, intolerances, medications, conditions, injuries, dietary restrictions (vegan, gluten-free, kosher, halal, etc.)
- Safety-relevant facts: phobias, triggers, anything a family member would need to know to avoid harm
- Strong preferences: foods they love or hate, drinks, brands, music, shows, hobbies they care about
- Relationships: spouse, kids, parents, siblings, pets — names, ages, roles
- Work and school: job title, employer, school, grade, major projects, schedule
- Location: where they live, work, travel often
- Recurring commitments: weekly appointments, standing plans, routines
- Dates: birthdays, anniversaries, important upcoming events
- Decisions and plans they've committed to ("I'm going to X on Thursday")
- Goals and ongoing projects

Also capture:
- Communication style preferences they've expressed ("be blunt with me", "don't use emojis")
- Tools, services, and accounts they use regularly

Skip:
- Already captured in existing memories (see below) — do not re-extract
- Pure speculation — only extract what was actually stated or strongly implied
- One-off task details ("asked about the weather today", "wanted a recipe for dinner")
- Generic small-talk with no factual content
- Facts about OTHER people unless the user's own relationship to them is the fact

Output format: JSON array of short strings, each a self-contained memory about the user. Write in third person starting with their name or a pronoun. Keep each under 180 characters. Be specific — "Jake is allergic to shellfish" beats "Jake has an allergy".

If nothing new is worth saving, return an empty array: []

Output ONLY the JSON array — no markdown, no code fences, no commentary.`;

const userPrompt = `Existing memories for ${speakerName}:
${existingBlock}

Recent conversation:
${historyText}
${speakerName}: ${userMessageText}
Bruce: ${assistantReplyText}

Return the JSON array of NEW memories to save for ${speakerName}.`;

return [{
  json: {
    ...router,
    memoryRequestBody: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 400,
      system,
      messages: [{ role: 'user', content: userPrompt }],
    },
  }
}];

// ---------------------------------------------------------------------------
// Parse Memory Extract
//
// Parses Haiku's JSON array of extracted memories. Emits one item per
// memory so the downstream Insert node runs once per row. Empty array → no
// output (nothing to insert). Parse failures are swallowed, returning [].
// ---------------------------------------------------------------------------
const router = $('Channel Router').first().json;
const apiRes = $input.item.json;
const speakerName = router.userName || 'the user';

const text = (apiRes.content || [])
  .filter(c => c.type === 'text')
  .map(c => c.text)
  .join('')
  .trim();

console.log(`[memory] raw text length=${text.length} for ${speakerName}`);

let memories = [];
try {
  // Strip code fences if the model wrapped output despite instructions.
  const cleaned = text
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();
  const parsedArr = JSON.parse(cleaned);
  if (Array.isArray(parsedArr)) {
    memories = parsedArr
      .filter(m => typeof m === 'string')
      .map(m => m.trim())
      .filter(m => m.length > 0);
  } else {
    console.log(`[memory] parsed JSON was not an array, got ${typeof parsedArr}`);
  }
} catch (err) {
  console.log(`[memory] parse failed: ${err.message} — raw first 300 chars: ${text.slice(0, 300)}`);
  memories = [];
}

if (memories.length === 0) {
  console.log(`[memory] no new memories extracted for ${speakerName}`);
} else {
  console.log(`[memory] extracted ${memories.length} new memories for ${speakerName}: ${JSON.stringify(memories)}`);
}

return memories.map(content => ({
  json: {
    ...router,
    memoryContent: content,
  }
}));

const message = $input.first().json.content || '';

const searchPatterns = [
  /near me|near here|near us|around here/i,
  /\b(latest|recent|current|today'?s?|this week|this month|right now)\b/i,
  /\b(news|score|price|weather|stock|update)\b/i,
  /\b(where can i|where to|best place|recommend.*restaurant|recommend.*shop)\b/i,
  /\b(who (is|are) (the current|currently))\b/i,
  /\b(is .+ (open|closed|available))\b/i,
  /\b(how much (does|is|are))\b/i,
  /\b(what('s| is) (happening|going on))\b/i,
];

const needsSearch = searchPatterns.some(p => p.test(message));

let searchQuery = message;
if (/near me|near here|near us|around here/i.test(message)) {
  searchQuery += ' Falls Church Merrifield VA';
}

return [{
  json: {
    ...$input.first().json,
    needs_search: needsSearch,
    search_query: searchQuery,
  }
}];

